string docIds = GetVariableValue("xWFData.SYS_DocIDs");

string remove1 = GetVariableValue("xWFData.SYS_UseStatement_DocID");

string[] allIds = docIds.Split('|');

string result = "";
for (int i = 0; i < allIds.Length; i++)
{
    string id = allIds[i];

    if (id != "" &&
        id != remove1)
    {
        if (result != "")
        {
            result += "|";
        }

        result += id;
    }
}

return result;

XmlNodeList RoutingOptionsList = _context.XmlVariables["dNextRouteSelection"].GetXmlNodes("//Row");

System.Xml.XmlDocument xWFDataXml = new XmlDocument();
var xWFData = _context.XmlVariables["xWFData"].GetXmlNode("//*").OuterXml;
xWFDataXml.LoadXml(xWFData);
System.Xml.XmlElement root = xWFDataXml.DocumentElement;

System.Xml.XPath.XPathNavigator requestNavigator = xWFDataXml.CreateNavigator();
bool found = false;

foreach(XmlNode RoutingOptionsNode in RoutingOptionsList){

    string condition = RoutingOptionsNode.SelectSingleNode("Condition").InnerText;

    if (condition != "" && !found) {
      System.Xml.XPath.XPathExpression expression = System.Xml.XPath.XPathExpression.Compile(condition);
      if (expression.ReturnType.Equals(System.Xml.XPath.XPathResultType.Boolean)){
        if ((bool)requestNavigator.Evaluate(expression)){

            XmlNode NodeSysRoute =  root.SelectSingleNode("//SYS_Route");
            string sNextRoute = RoutingOptionsNode.SelectSingleNode("NextRoute").InnerText;
            NodeSysRoute.InnerText = sNextRoute;

            found = true;
        }
      }
    }
}

return xWFDataXml.OuterXml;

