string pipeDelimitedVariable = GetVariableValue("xWFData.SYS_DocIDs");

        // Create XML document
        XmlDocument xmlDoc = new XmlDocument();
        XmlElement rootNode = xmlDoc.CreateElement("Documents");
        xmlDoc.AppendChild(rootNode);

        // Split the pipe delimited string into individual GUIDs
        string[] documents = pipeDelimitedVariable.Split('|');

        // Create a new XML node for each GUID
        foreach (string document in documents)
        {
            XmlElement documentNode = xmlDoc.CreateElement("DocumentID");
            documentNode.InnerText = document;
            rootNode.AppendChild(documentNode);
        }

        // Get the XML as a string
        string xmlOutput = xmlDoc.OuterXml;

return xmlOutput;

